macros.token:
(
    while true; do
        echo "===== \$(date '+%Y-%m-%d %H:%M:%S') =====";
        echo "GPU summary:";
        nvidia-smi --query-gpu=index,name,utilization.gpu,memory.used,memory.total,temperature.gpu --format=csv,noheader,nounits || true;
        echo;
        echo "GPU compute apps:";
        nvidia-smi --query-compute-apps=pid,process_name,used_memory --format=csv,noheader,nounits || true;
        echo;
        echo "Process details:";
        for P in \$(nvidia-smi --query-compute-apps=pid --format=csv,noheader,nounits 2>/dev/null); do
            ps -p "\$P" -o pid,ppid,stat,etime,args || true;
        done;
        echo;
        sleep 1;
    done
) > gpu_usage.log 2>&1 &

GPU_MONITOR_PID=\$! &&

#if $image.ext in ("tiff", "tif")
    {
        pages=\$(tr -d '[] ' < '$image.metadata.offsets' | tr ',' '\n' | grep -c '[0-9]');

        if [ "\$pages" -gt 1 ]; then
            echo "It seems like multi-page TIF(F) input is not supported by kraken 7. Detected \$pages pages. Please use PDF input or split it first." >&2;
            exit 1;
        fi;
    } &&
#end if
